import { useEffect, useState }
from "react";

import API
from "../services/api";

function TransactionList() {

  const [transactions,
    setTransactions] =
    useState([]);





  useEffect(() => {

    fetchTransactions();

  }, []);






  const fetchTransactions =
    async () => {

    try {

      const token =
        localStorage.getItem(
          "token"
        );

      const response =
        await API.get(
          "/transactions",
          {
            headers: {
              Authorization:
                `Bearer ${token}`,
            },
          }
        );

      setTransactions(
        response.data
      );

    } catch (error) {

      console.log(error);

    }
  };








  return (

    <div
      className="
      bg-white
      rounded-xl
      shadow-lg
      p-6
      mt-10
    "
    >

      <h2
        className="
        text-2xl
        font-bold
        mb-6
      "
      >
        Recent Transactions
      </h2>







      <div
        className="
        overflow-x-auto
      "
      >

        <table
          className="
          w-full
          border-collapse
        "
        >

          <thead>

            <tr
              className="
              bg-gray-200
            "
            >

              <th className="p-3">
                Type
              </th>

              <th className="p-3">
                Category
              </th>

              <th className="p-3">
                Amount
              </th>

              <th className="p-3">
                Description
              </th>

            </tr>

          </thead>








          <tbody>

            {
              transactions.map(
                (item) => (

                <tr
                  key={item._id}
                  className="
                  border-b
                "
                >

                  <td className="p-3">
                    {item.type}
                  </td>

                  <td className="p-3">
                    {item.category}
                  </td>

                  <td className="p-3">
                    ₹{item.amount}
                  </td>

                  <td className="p-3">
                    {item.description}
                  </td>

                </tr>

              ))
            }

          </tbody>

        </table>

      </div>

    </div>
  );
}

export default TransactionList;
